import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/axios';

const AdminPage = () => {
  const navigate = useNavigate();

  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [comments, setComments] = useState([]);
  const [messages, setMessages] = useState([]);
  const [tab, setTab] = useState('users');
  const [search, setSearch] = useState('');

  // ================= FETCH DATA =================
  useEffect(() => {
    API.get('/admin/users').then(res => setUsers(res.data || []));
    API.get('/admin/posts').then(res => setPosts(res.data || []));
    API.get('/admin/comments').then(res => setComments(res.data || []));
    API.get('/admin/messages').then(res => setMessages(res.data || []));
  }, []);

  // ================= USER ACTIONS =================
  const toggleStatus = async (id) => {
    try {
      const { data } = await API.put(`/admin/users/${id}/status`);
      setUsers(prev => prev.map(u => (u._id === id ? data.user : u)));
    } catch {
      alert("Error updating user status.");
    }
  };

  // ================= POST ACTIONS =================
  const removePost = async (id) => {
    if (!window.confirm("Delete this post?")) return;
    try {
      await API.delete(`/posts/${id}`);
      setPosts(prev => prev.filter(p => p._id !== id));
    } catch {
      alert("Error deleting post.");
    }
  };

  const viewPost = (id) => navigate(`/posts/${id}`);

  // ================= COMMENT ACTIONS =================
  const deleteComment = async (id) => {
    try {
      await API.delete(`/comments/${id}`);
      setComments(prev => prev.filter(c => c._id !== id));
    } catch {
      alert("Error deleting comment.");
    }
  };

  // ================= MESSAGE ACTIONS =================
  const markAsRead = async (id) => {
    try {
      await API.put(`/admin/messages/${id}/read`);

      // ✅ Force update locally (important)
      setMessages(prev =>
        prev.map(m =>
          m._id === id
            ? { ...m, status: 'read', read: true, isRead: true }
            : m
        )
      );
    } catch {
      alert("Error marking message as read.");
    }
  };

  const deleteMessage = async (id) => {
    try {
      await API.delete(`/admin/messages/${id}`);
      setMessages(prev => prev.filter(m => m._id !== id));
    } catch {
      alert("Error deleting message.");
    }
  };

  // ================= SEARCH FILTER =================
  const filterData = () => {
    const keyword = search.toLowerCase();

    if (tab === 'users') {
      return users.filter(u =>
        u.name?.toLowerCase().includes(keyword) ||
        u.email?.toLowerCase().includes(keyword)
      );
    }

    if (tab === 'posts') {
      return posts.filter(p =>
        p.title?.toLowerCase().includes(keyword) ||
        p.author?.name?.toLowerCase().includes(keyword)
      );
    }

    if (tab === 'comments') {
      return comments.filter(c =>
        c.body?.toLowerCase().includes(keyword) ||
        c.author?.name?.toLowerCase().includes(keyword)
      );
    }

    if (tab === 'messages') {
      return messages.filter(m =>
        m.name?.toLowerCase().includes(keyword) ||
        m.email?.toLowerCase().includes(keyword) ||
        m.message?.toLowerCase().includes(keyword) ||
        m.body?.toLowerCase().includes(keyword)
      );
    }

    return [];
  };

  const filteredData = filterData();

  // ================= STATUS HELPER =================
  const getMessageStatus = (m) => {
    return (m.status === 'read' || m.read || m.isRead) ? 'READ' : 'NEW';
  };

  const isMessageRead = (m) => {
    return (m.status === 'read' || m.read || m.isRead);
  };

  // ================= STYLES =================
  const styles = {
    page: { padding: '30px', fontFamily: 'Segoe UI' },
    tabs: { display: 'flex', gap: '10px', marginBottom: '20px' },
    tab: { padding: '10px 20px', cursor: 'pointer' },
    active: { background: '#0c4b34', color: '#fff' },
    search: {
      padding: '10px',
      marginBottom: '15px',
      width: '100%',
      borderRadius: '10px',
      border: '1px solid #ccc'
    },
    table: { width: '100%', borderCollapse: 'collapse' },
    th: { background: '#0c4b34', color: '#fff', padding: '10px' },
    td: { padding: '10px', borderBottom: '1px solid #ddd' },
    btn: { padding: '6px 12px', margin: '2px', cursor: 'pointer' }
  };

  return (
    <div style={styles.page}>
      <h2>Admin Portal</h2>

      {/* TABS */}
      <div style={styles.tabs}>
        {['users', 'posts', 'comments', 'messages'].map(t => (
          <button
            key={t}
            onClick={() => setTab(t)}
            style={{ ...styles.tab, ...(tab === t ? styles.active : {}) }}
          >
            {t.toUpperCase()}
          </button>
        ))}
      </div>

      {/* SEARCH */}
      <input
        type="text"
        placeholder={`Search ${tab}...`}
        value={search}
        onChange={(e) => setSearch(e.target.value)}
        style={styles.search}
      />

      {/* TABLE */}
      <table style={styles.table}>
        <thead>
          {tab === 'users' && (
            <tr>
              <th style={styles.th}>Name</th>
              <th style={styles.th}>Email</th>
              <th style={styles.th}>Status</th>
              <th style={styles.th}>Action</th>
            </tr>
          )}
          {tab === 'posts' && (
            <tr>
              <th style={styles.th}>Title</th>
              <th style={styles.th}>Author</th>
              <th style={styles.th}>Action</th>
            </tr>
          )}
          {tab === 'comments' && (
            <tr>
              <th style={styles.th}>Author</th>
              <th style={styles.th}>Comment</th>
              <th style={styles.th}>Action</th>
            </tr>
          )}
          {tab === 'messages' && (
            <tr>
              <th style={styles.th}>Name</th>
              <th style={styles.th}>Email</th>
              <th style={styles.th}>Message</th>
              <th style={styles.th}>Status</th>
              <th style={styles.th}>Action</th>
            </tr>
          )}
        </thead>

        <tbody>
          {/* USERS */}
          {tab === 'users' && filteredData.map(u => (
            <tr key={u._id}>
              <td style={styles.td}>{u.name}</td>
              <td style={styles.td}>{u.email}</td>
              <td style={styles.td}>{u.status?.toUpperCase()}</td>
              <td style={styles.td}>
                <button style={styles.btn} onClick={() => toggleStatus(u._id)}>
                  Toggle
                </button>
              </td>
            </tr>
          ))}

          {/* POSTS */}
          {tab === 'posts' && filteredData.map(p => (
            <tr key={p._id}>
              <td style={styles.td}>{p.title}</td>
              <td style={styles.td}>{p.author?.name}</td>
              <td style={styles.td}>
                <button style={styles.btn} onClick={() => viewPost(p._id)}>View</button>
                <button style={styles.btn} onClick={() => removePost(p._id)}>Delete</button>
              </td>
            </tr>
          ))}

          {/* COMMENTS */}
          {tab === 'comments' && filteredData.map(c => (
            <tr key={c._id}>
              <td style={styles.td}>{c.author?.name}</td>
              <td style={styles.td}>{c.body}</td>
              <td style={styles.td}>
                <button style={styles.btn} onClick={() => deleteComment(c._id)}>
                  Delete
                </button>
              </td>
            </tr>
          ))}

          {/* MESSAGES */}
          {tab === 'messages' && filteredData.map(m => (
            <tr key={m._id}>
              <td style={styles.td}>{m.name}</td>
              <td style={styles.td}>{m.email}</td>
              <td style={styles.td}>{m.body ?? m.message}</td>
              <td style={styles.td}>{getMessageStatus(m)}</td>
              <td style={styles.td}>
                {!isMessageRead(m) && (
                  <button style={styles.btn} onClick={() => markAsRead(m._id)}>
                    Mark Read
                  </button>
                )}
                <button style={styles.btn} onClick={() => deleteMessage(m._id)}>
                  Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default AdminPage;
